package main

import "fmt"

func main() {
	var n int
	fmt.Scan(&n)
	v := make([]int, n)
	for i := range v {
		fmt.Scan(&v[i])
	}
	var target int
	fmt.Scan(&target)
	lo, hi, ans := 0, n-1, -1
	for lo <= hi {
		mid := (lo + hi) / 2
		if v[mid] == target {
			ans = mid
			break
		} else if v[mid] < target {
			lo = mid + 1
		} else {
			hi = mid - 1
		}
	}
	fmt.Println(ans)
}
